<style type="text/css" lang="scss">
.tip-info {
  padding: 8px 16px;
  background-color: #fff6f7;
  border-radius: 4px;
  border-left: 5px solid #ff7800;
  margin: 11px 0;
}
</style>
<template>
  <div>
    <el-tabs v-model="activeName" type="border-card" @tab-click="handleClick">
      <div class="tip-info">
        <p>
          上傳文件如果有處理失敗的數據後將會生成錯誤文件，請及時查看錯誤訊息修改後重新下載，錯誤描述文件只保留<strong>15天</strong>。
        </p>
        <p>超過<strong>15天</strong>的錯誤描述文件將會刪除，不再提供下載查看</p>
      </div>
      <el-form ref="form" label-width="100px">
        <div class="content-bottom-padded">
          <el-upload
            class="fl"
            style="margin-right: 10px"
            action=""
            :on-change="uploadHandleChange"
            :auto-upload="false"
            :show-file-list="false"
          >
            <el-button size="small" type="primary"> 點擊上傳 </el-button>
          </el-upload>
          <el-button size="small" type="primary" @click="uploadHandleTemplate()">
            下載模組
          </el-button>
        </div>
        <el-table
          v-loading="loading"
          :data="uploadList"
          :height="wheight - 240"
          element-loading-text="數據加載中"
        >
          <el-table-column prop="file_name" label="上傳文件" min-width="100" />
          <el-table-column prop="created_date" label="上傳時間" min-width="80" />
          <el-table-column prop="file_size_format" label="文件大小" min-width="60" />
          <el-table-column label="處理狀態" min-width="50">
            <template slot-scope="scope">
              <span v-if="scope.row.handle_status == 'wait'">等待處理</span>
              <span v-if="scope.row.handle_status == 'processing'">處理中</span>
              <span v-if="scope.row.handle_status == 'finish'">處理完成</span>
            </template>
          </el-table-column>
          <el-table-column prop="finish_date" label="處理完成時間" />
          <el-table-column label="處理成功">
            <template slot-scope="scope">
              <span v-if="scope.row.handle_message"
                >{{ scope.row.handle_message.successLine }}行</span
              >
            </template>
          </el-table-column>
          <el-table-column label="處理失敗">
            <template slot-scope="scope">
              <span v-if="scope.row.handle_message"
                >{{ scope.row.handle_message.errorLine }}行</span
              >
              <a
                v-if="scope.row.handle_message && scope.row.handle_message.errorLine > 0"
                type="primary"
                @click="exportErrorFile(scope.row.id, scope.row.file_type)"
                >下載錯誤詳情</a
              >
            </template>
          </el-table-column>
        </el-table>
        <div v-if="total_count > pageSize" class="content-top-padded content-center">
          <el-pagination
            layout="total, prev, pager, next"
            :total="total_count"
            :page-size="pageSize"
            @current-change="handleCurrentChange"
          />
        </div>
      </el-form>
    </el-tabs>
  </div>
</template>
<script>
import { mapGetters } from 'vuex'
import {
  handleUploadFile,
  getUploadLists,
  exportUploadErrorFile,
  exportUploadTemplate
} from '../../../api/common'

export default {
  data() {
    return {
      // pane_list: [
      //   { name: 'member_consume', label: '上傳消費金額' },
      //   { name: 'member_info', label: '上傳新會員' },
      //   { name: 'member_update', label: '更新會員' },
      //   { name: 'selform_registration_record', label: '上傳報名審核結果' },
      //   { name: 'community_chief', label: '上傳團長訊息' },
      // ],
      loading: false,
      total_count: 0,
      pageSize: 20,
      page: 1,
      activeName: 'community_chief',
      uploadList: []
    }
  },
  computed: {
    ...mapGetters(['wheight'])
  },
  mounted() {
    this.getUploadList()
  },
  methods: {
    handleClick() {
      this.getUploadList()
    },
    uploadHandleChange(file, fileList) {
      let params = { isUploadFile: true, file_type: this.activeName, file: file.raw }
      handleUploadFile(params).then((response) => {
        this.$message({
          type: 'success',
          message: '上傳成功，等待處理'
        })
        this.getUploadList()
      })
    },
    uploadHandleTemplate() {
      if (this.activeName == 'member_info') {
        var fileName = '新增會員訊息'
      } else if (this.activeName == 'member_update') {
        var fileName = '更新會員訊息'
      } else if (this.activeName == 'community_chief') {
        var fileName = '上傳團長訊息'
      }
      let params = { file_type: this.activeName, file_name: fileName }
      exportUploadTemplate(params).then((response) => {
        if (response.data.data.file) {
          var a = document.createElement('a')
          a.href = response.data.data.file
          a.download = response.data.data.name
          document.body.appendChild(a)
          a.click()
          a.remove()
        } else {
          this.$message({
            type: 'error',
            message: '沒有相關數據可匯出'
          })
        }
      })
    },
    exportErrorFile(id, fileType) {
      let params = { file_type: fileType }
      exportUploadErrorFile(id, params).then((response) => {
        if (response.data.data.file) {
          var a = document.createElement('a')
          a.href = response.data.data.file
          a.download = response.data.data.name
          document.body.appendChild(a)
          a.click()
          a.remove()
        } else {
          this.$message({
            type: 'error',
            message: '沒有相關數據可匯出'
          })
        }
      })
    },
    handleCurrentChange(val) {
      this.page = val
      this.getUploadList()
    },
    getUploadList() {
      this.loading = true
      let params = { file_type: this.activeName, page: this.page, pageSize: this.pageSize }
      getUploadLists(params).then((response) => {
        this.uploadList = response.data.data.list
        this.total_count = response.data.data.total_count
        this.loading = false
      })
    }
  }
}
</script>
